namespace DevSwarm.Completion.Api.Configuration;

public static class RateLimitingExtensions
{
    public static IServiceCollection AddDevSwarmRateLimiting(this IServiceCollection services, IConfiguration config)
    {
        services.AddRateLimiter(options =>
        {
            options.AddSlidingWindowLimiter("userip", slidingWindowOptions =>
            {
                slidingWindowOptions.PermitLimit = 10;
                slidingWindowOptions.Window = TimeSpan.FromMinutes(1);
                slidingWindowOptions.SegmentsPerWindow = 6;
                slidingWindowOptions.QueueLimit = 0;
            });

            options.OnRejected = async (context, token) =>
            {
                context.HttpContext.Response.StatusCode = 429;
                await context.HttpContext.Response.WriteAsync("Rate limit exceeded", token);
            };
        });

        return services;
    }
